1	/**
2	 * 任务1-4: factor_baselines.json 初始化 + 阶段标签修正 + SOON层建卡 + 冷层/冷冻分层
3	 *
4	 * 输入: heat_classification.json (466人)
5	 * 输出: factor_baselines.json, SOON清单, 冷层/冷冻层清单
6	 */
7	
8	const fs = require('fs');
9	const path = require('path');
10	
11	const TODAY = '2026-05-18';
12	const TODAY_DATE = new Date(TODAY);
13	
14	// ============ 配置 ============
15	
16	/** 旧阶段 → 新9阶段映射 */
17	const STAGE_MAP = {
18	  '需求探索': '需求探索',
19	  '报价已发': '报价已发',
20	  '谈判中': '谈判中',
21	  '待付款': '待付款',
22	  '待发货': '待发货',
23	  '已发货/在途': '已发货/在途',
24	  '已签收': '已签收',
25	  '售后': '售后',
26	  '待返单': '待返单',
27	  // 旧标签映射
28	  '初询沟通': '需求探索',
29	  'PI已发': '报价已发',
30	  '谈判/样品': '谈判中',
31	  '样品阶段': '谈判中',  // 保守: 未付款→谈判中
32	  // 未知保持null→冷层
33	  '未知': null,
34	};
35	
36	/** SOON因子节奏表 (V6) — 绝对天数制（非累加间隔） */
37	const RHYTHM = {
38	  S1:  [1, 3, 7, 15, 30],             // 需求探索 第1/3/7/15/30天 → 放弃
39	  S2:  [1, 3, 7, 15, 30],             // 报价已发 第1/3/7/15/30天 → 放弃
40	  S3:  [1, 3, 5, 7, 15, 30],          // 谈判中 第1/3/5/7/15/30天 → 放弃？待确认
41	  S4:  [1, 3, 5, 7, 15],              // 待付款 第1/3/5/7/15天 → 降级
42	  S8:  [1, 2, 3, 5, 7, 15, 30],       // 售后 第1/2/3/5/7/15/30天 → 放弃？待确认
43	  // 以下因子仍为累加间隔制（含重复值，非绝对天数）：
44	  S7a: [1, 3, 7, 30, 60],             // 已签收 该回访了 D1→D3→D7→D30→D60停止
45	  S7b_sample: [7],                     // 样品单 该推返单
46	  S7b_bulk: [30],                      // 大货 该推返单
47	  S9_sample: [1, 3, 7, 30, 60],       // 待返单(样品) D1→D3→D7→D30→D60停止
48	  S9_bulk:   [1, 7, 15, 30, 45, 60, 75, 90],  // 待返单(大货) D1→D7→D15→...→D90结束
49	};
50	// 终止型因子：最后节点±1天后不再提醒
51	const TERMINAL_FACTORS = new Set(['S1', 'S2', 'S7a', 'S9']);
52	
53	/** S5a 双基线间隔计算 */
54	function s5aInterval(meta) {
55	  if (meta.customer_type === '样品单') return 3;
56	  if (!meta.transit_days) return 7; // 默认大货交期35天÷5≈7
57	  const interval = Math.round(meta.transit_days / 5);
58	  return Math.max(3, Math.min(10, interval));
59	}
60	
61	/** S6 间隔: 时效÷N */
62	function s6Interval(meta) {
63	  const transitDays = meta.transit_days || 25;
64	  const N = { S: 6, A: 6, B: 5, C: 5, D: 4 }[meta.customer_tier] || 5;
65	  const interval = Math.round(transitDays / N);
66	  return Math.max(2, Math.min(15, interval));
67	}
68	
69	// ============ 辅助函数 ============
70	
71	function parseDate(str) {
72	  if (!str) return null;
73	  const d = new Date(str);
74	  return isNaN(d.getTime()) ? null : d;
75	}
76	
77	function daysBetween(d1, d2) {
78	  return Math.floor((d2.getTime() - d1.getTime()) / (1000 * 60 * 60 * 24));
79	}
80	
81	/** 判定节奏命中：rhythmArr 为绝对天数（如[1,3,7]=第1/3/7天）。最后一个节点无限上界，终止型因子最后也±1天就停 */
82	function rhythmHit(days, rhythmArr, factorCode) {
83	  const isTerminal = factorCode && TERMINAL_FACTORS.has(factorCode);
84	  for (let i = rhythmArr.length - 1; i >= 0; i--) {
85	    const targetDay = rhythmArr[i];  // 绝对天数，非累加
86	    if (days < targetDay) continue;
87	    if (isTerminal) return (days <= targetDay + 1) ? i : -1;
88	    if (i === rhythmArr.length - 1) return i;
89	    if (days <= targetDay + 1) return i;
90	  }
91	  return -1;
92	}
93	
94	/** 获取客户等级 (从 dashboard_snapshot 交叉匹配或默认) */
95	let tierMap = null;
96	function loadTierMap() {
97	  if (tierMap) return tierMap;
98	  tierMap = new Map();
99	  try {
100	    const snap = JSON.parse(fs.readFileSync(
101	      path.join(__dirname, '..', 'output', '.dashboard_snapshot.json'), 'utf-8'
102	    ));
103	    for (const c of snap.customers || []) {
104	      const key = (c.name || '').toLowerCase() + '|' + (c.country || '');
105	      tierMap.set(key, c.quality || 'C');
106	    }
107	  } catch (e) { /* ignore */ }
108	  return tierMap;
109	}
110	
111	function getTierWithSource(name, country) {
112	  const map = loadTierMap();
113	  const key = (name || '').toLowerCase().trim() + '|' + (country || '').toUpperCase().trim();
114	  const matched = map.get(key);
115	  if (matched) return { tier: matched, source: 'dashboard_snapshot' };
116	  return { tier: 'C', source: 'default_C' };
117	}
118	
119	/** 加载订单数据 → 客户名→状态查找表 */
120	function loadOrderMap() {
121	  const map = new Map();
122	  try {
123	    const ordersPath = path.join(__dirname, '..', 'data', 'orders_latest.json');
124	    if (fs.existsSync(ordersPath)) {
125	      const orders = JSON.parse(fs.readFileSync(ordersPath, 'utf-8'));
126	      for (const o of orders.orders || []) {
127	        const nameKey = (o.customer || '').toLowerCase().trim();
128	        if (nameKey) map.set(nameKey, o);
129	      }
130	    }
131	  } catch (e) { /* ignore */ }
132	  return map;
133	}
134	
135	/** 用订单数据校正阶段标签 */
136	function correctStageByOrder(name, currentStage, orderMap) {
137	  const nameKey = (name || '').toLowerCase().trim();
138	  const order = orderMap.get(nameKey);
139	  if (!order) return { stage: currentStage, orderStatus: null, paymentConfirmed: false };
140	
141	  const st = order.status;
142	  // 待发货 → 订单状态实际是其他，需要修正
143	  if (currentStage === '待发货') {
144	    if (st === '待收款') return { stage: '待付款', orderStatus: st, paymentConfirmed: false };
145	    if (st === '已发货') return { stage: '已发货/在途', orderStatus: st, paymentConfirmed: true };
146	    if (st === '交易成功') return { stage: '已签收', orderStatus: st, paymentConfirmed: true };
147	    if (st === '交易取消') return { stage: '未成交', orderStatus: st, paymentConfirmed: false };
148	    if (st === '待发货') return { stage: currentStage, orderStatus: st, paymentConfirmed: true };
149	    return { stage: currentStage, orderStatus: st, paymentConfirmed: false };
150	  }
151	  // 待付款 → 实际已发货/已完成
152	  if (currentStage === '待付款') {
153	    if (st === '已发货') return { stage: '已发货/在途', orderStatus: st, paymentConfirmed: true };
154	    if (st === '交易成功') return { stage: '已签收', orderStatus: st, paymentConfirmed: true };
155	    if (st === '交易取消') return { stage: '未成交', orderStatus: st, paymentConfirmed: false };
156	    if (st === '待收款') return { stage: currentStage, orderStatus: st, paymentConfirmed: false };
157	    return { stage: currentStage, orderStatus: st, paymentConfirmed: st === '待发货' };
158	  }
159	  // 其他阶段: 仅记录订单状态
160	  return { stage: currentStage, orderStatus: st, paymentConfirmed: (st === '待发货' || st === '已发货' || st === '交易成功') };
161	}
162	
163	/** 判定 target_market 是否非洲/中东 */
164	function isAfricaOrMiddleEast(country) {
165	  const africaME = ['SD','EG','CD','ZM','CI','SA','AE','IQ','GH','NG','KE','TZ','UG','ET','CM','SN','ML','BF','BJ','TG','LY','MA','DZ','TN','KW','QA','BH','OM','JO','LB','YE','SY','PS','CG','GA','MR','SO'];
166	  return africaME.includes((country || '').toUpperCase());
167	}
168	
169	// ============ 主流程 ============
170	
171	function checkFreshness() {
172	  const p = path.join(__dirname, '..', 'data', '.last_sync.json');
173	  if (!fs.existsSync(p)) {
174	    console.log('⚠️  无同步记录，建议先运行 sync_okki.js');
175	    return;
176	  }
177	  const { date, count } = JSON.parse(fs.readFileSync(p, 'utf-8'));
178	  const daysAgo = daysBetween(new Date(date), TODAY_DATE);
179	  if (daysAgo > 0) console.log(`⚠️  数据 ${daysAgo} 天前同步（${date}），有疑问请先 sync`);
180	  else console.log(`✅ 今日已同步 ${count} 会话`);
181	}
182	
183	function main() {
184	  checkFreshness();
185	  // 读取源数据
186	  const srcPath = path.join(__dirname, '..', 'data', 'heat_classification.json');
187	  const data = JSON.parse(fs.readFileSync(srcPath, 'utf-8'));
188	  const customers = data.results;
189	  console.log(`读取 ${customers.length} 条客户记录`);
190	
191	  // 加载订单数据用于阶段交叉验证
192	  const orderMap = loadOrderMap();
193	
194	  const baselines = {};
195	  const stageStats = {};       // 新阶段统计
196	  const stageCorrections = []; // 阶段修正记录
197	  const soonCustomers = [];    // SOON层清单
198	  const coldCustomers = [];    // 冷层清单
199	  const frozenLayers = {       // 冷冻层分层
200	    highValue: [],   // 高价值沉睡 (S/A/B级)
201	    deepFrozen: [],  // 深度冷冻 (C级>180天)
202	    normal: [],      // 普通沉睡
203	    neverDeal: [],   // 从未成交 (D级)
204	  };
205	
206	  for (const c of customers) {
207	    const oldStage = c.stage;
208	    const mappedStage = STAGE_MAP[oldStage];
209	
210	    // 订单数据交叉验证
211	    const orderCorrection = correctStageByOrder(c.name, mappedStage, orderMap);
212	    const newStage = orderCorrection.stage;
213	    if (newStage !== mappedStage) {
214	      stageCorrections.push({
215	        cid: c.cid, name: c.name,
216	        oldStage: `${oldStage}→${mappedStage}`,
217	        newStage: orderCorrection.stage,
218	        reason: `订单状态=${orderCorrection.orderStatus}`,
219	      });
220	    }
221	
222	    // 统计（始终记录旧标签→新标签）
223	    stageStats[oldStage] = (stageStats[oldStage] || 0) + 1;
224	
225	    const tierInfo = getTierWithSource(c.name, c.country);
226	    const tier = tierInfo.tier;
227	    const lastMsgDate = parseDate(c.lastMsgTime);
228	    const daysSinceMsg = lastMsgDate ? daysBetween(lastMsgDate, TODAY_DATE) : 999;
229	    const lastSenderIsMe = c.lastSender === '我';
230	
231	    // 初始化 meta
232	    const meta = {
233	      transit_days: null,
234	      customer_tier: tier,
235	      _tier_source: tierInfo.source,
236	      committed_ship_date: null,
237	      has_address: null,
238	      customer_type: (oldStage === '样品阶段') ? '样品单' : '大货',
239	      repurchase_cycle_days: null,
240	      target_market: isAfricaOrMiddleEast(c.country) ? 'africa_me' : 'other',
241	      s8_boundary_checked: false,
242	      _payment_confirmed: orderCorrection.paymentConfirmed,
243	      _order_status: orderCorrection.orderStatus,
244	    };
245	
246	    // 初始化 baselines (全部 null)
247	    const bl = { S1: null, S2: null, S3: null, S4: null, S5a_A: null, S5a_B: null, S6: null, S7a: null, S7b: null, S8: null, S9: null };
248	
249	    const stageUpdated = null;
250	
251	    if (newStage) {
252	      // 根据阶段设置对应基线
253	      switch (newStage) {
254	        case '需求探索':
255	          if (lastSenderIsMe) bl.S1 = c.lastMsgTime;
256	          break;
257	        case '报价已发':
258	          bl.S2 = c.lastMsgTime;
259	          break;
260	        case '谈判中':
261	          bl.S3 = c.lastMsgTime;
262	          break;
263	        case '待付款':
264	          bl.S4 = c.lastMsgTime;
265	          break;
266	        case '待发货':
267	          if (lastSenderIsMe) bl.S5a_A = c.lastMsgTime;
268	          break;
269	        case '已发货/在途':
270	          bl.S6 = c.lastMsgTime;
271	          meta.transit_days = isAfricaOrMiddleEast(c.country) ? 30 : 25;
272	          break;
273	        case '已签收':
274	          bl.S7a = c.lastMsgTime;
275	          bl.S7b = c.lastMsgTime;
276	          break;
277	        case '售后':
278	          if (lastSenderIsMe) bl.S8 = c.lastMsgTime;
279	          break;
280	        case '待返单':
281	          bl.S9 = c.lastMsgTime;
282	          break;
283	      }
284	
285	      // 计算 SOON 因子命中
286	      const factors = computeFactors(newStage, bl, meta, daysSinceMsg, lastSenderIsMe);
287	
288	      baselines[c.cid] = {
289	        name: c.name,
290	        country: c.country,
291	        stage: newStage,
292	        stage_updated: stageUpdated,
293	        baselines: bl,
294	        meta,
295	        _heat: c.heat,
296	        _daysSinceLastContact: c.daysSinceLastContact,
297	      };
298	
299	      if (factors.length > 0) {
300	        soonCustomers.push({
301	          cid: c.cid,
302	          name: c.name,
303	          country: c.country,
304	          stage: newStage,
305	          heat: c.heat,
306	          tier,
307	          daysSinceLastContact: c.daysSinceLastContact,
308	          factors,
309	        });
310	      }
311	    } else {
312	      // 未知阶段 → 冷层
313	      baselines[c.cid] = {
314	        name: c.name,
315	        country: c.country,
316	        stage: null,
317	        stage_updated: null,
318	        baselines: bl,
319	        meta,
320	        _heat: c.heat,
321	        _daysSinceLastContact: c.daysSinceLastContact,
322	      };
323	      coldCustomers.push({
324	        cid: c.cid,
325	        name: c.name,
326	        country: c.country,
327	        daysSinceLastContact: c.daysSinceLastContact,
328	        tier,
329	        lastMsgTime: c.lastMsgTime,
330	        lastSender: c.lastSender,
331	      });
332	    }
333	  }
334	
335	  // 冷冻层分层
336	  for (const cc of coldCustomers) {
337	    if (cc.tier === 'S' || cc.tier === 'A' || cc.tier === 'B') {
338	      frozenLayers.highValue.push(cc);
339	    } else if (cc.tier === 'C' && cc.daysSinceLastContact > 180) {
340	      frozenLayers.deepFrozen.push(cc);
341	    } else if (cc.tier === 'D') {
342	      frozenLayers.neverDeal.push(cc);
343	    } else {
344	      frozenLayers.normal.push(cc);
345	    }
346	  }
347	
348	  // ==== 输出统计 ====
349	  console.log('\n===== 阶段映射统计 =====');
350	  for (const [k, v] of Object.entries(stageStats).sort((a, b) => b[1] - a[1])) {
351	    const mapped = STAGE_MAP[k];
352	    const arrow = mapped === k ? '→ 不变' : mapped === null ? '→ 冷层' : `→ ${mapped}`;
353	    console.log(`  ${k}: ${v} ${arrow}`);
354	  }
355	
356	  const newStageCounts = {};
357	  for (const v of Object.values(baselines)) {
358	    const s = v.stage || '未知(冷层)';
359	    newStageCounts[s] = (newStageCounts[s] || 0) + 1;
360	  }
361	  console.log('\n===== 新9阶段分布 =====');
362	  for (const [k, v] of Object.entries(newStageCounts).sort((a, b) => b[1] - a[1])) {
363	    console.log(`  ${k}: ${v}`);
364	  }
365	
366	  console.log(`\n===== SOON层: ${soonCustomers.length}人 =====`);
367	  console.log(`===== 冷层: ${coldCustomers.length}人 =====`);
368	  console.log(`  高价值沉睡 (S/A/B级): ${frozenLayers.highValue.length}`);
369	  console.log(`  深度冷冻 (C级>180天): ${frozenLayers.deepFrozen.length}`);
370	  console.log(`  普通沉睡: ${frozenLayers.normal.length}`);
371	  console.log(`  从未成交 (D级): ${frozenLayers.neverDeal.length}`);
372	
373	  // ==== 写入文件 ====
374	
375	  // 1. factor_baselines.json
376	  const outDir = path.join(__dirname, '..', 'output');
377	  const baselinesOut = {};
378	  for (const [cid, val] of Object.entries(baselines)) {
379	    const { _heat, _daysSinceLastContact, ...rest } = val;
380	    baselinesOut[cid] = rest;
381	  }
382	  fs.writeFileSync(
383	    path.join(outDir, 'factor_baselines.json'),
384	    JSON.stringify(baselinesOut, null, 2),
385	    'utf-8'
386	  );
387	  console.log('\n✅ factor_baselines.json 已写入');
388	
389	  // 2. 阶段修正记录
390	  fs.writeFileSync(
391	    path.join(outDir, 'stage_corrections.json'),
392	    JSON.stringify({ date: TODAY, corrections: stageCorrections, total: stageCorrections.length }, null, 2),
393	    'utf-8'
394	  );
395	  console.log(`✅ stage_corrections.json 已写入 (${stageCorrections.length}条修正)`);
396	
397	  // 3. SOON层清单
398	  const soonOutput = {
399	    date: TODAY,
400	    total: soonCustomers.length,
401	    summary: summarizeFactors(soonCustomers),
402	    customers: soonCustomers.sort((a, b) => {
403	      // NOW优先，然后按因子数降序
404	      if (a.heat === 'NOW' && b.heat !== 'NOW') return -1;
405	      if (b.heat === 'NOW' && a.heat !== 'NOW') return 1;
406	      return b.factors.length - a.factors.length;
407	    }),
408	  };
409	  fs.writeFileSync(
410	    path.join(outDir, 'soon_layer_cards.json'),
411	    JSON.stringify(soonOutput, null, 2),
412	    'utf-8'
413	  );
414	  console.log(`✅ soon_layer_cards.json 已写入`);
415	
416	  // 4. 冷层+冷冻分层
417	  const coldOutput = {
418	    date: TODAY,
419	    total: coldCustomers.length,
420	    frozen: {
421	      highValueDormant: frozenLayers.highValue,
422	      deepFrozen: frozenLayers.deepFrozen,
423	      normalDormant: frozenLayers.normal,
424	      neverDeal: frozenLayers.neverDeal,
425	    },
426	  };
427	  fs.writeFileSync(
428	    path.join(outDir, 'cold_layer_stratification.json'),
429	    JSON.stringify(coldOutput, null, 2),
430	    'utf-8'
431	  );
432	  console.log(`✅ cold_layer_stratification.json 已写入`);
433	
434	  // 5. 汇总报告 (markdown)
435	  const report = generateReport(newStageCounts, soonOutput, coldOutput, stageCorrections);
436	  fs.writeFileSync(path.join(outDir, 'init_report_2026-05-18.md'), report, 'utf-8');
437	  console.log(`✅ init_report_2026-05-18.md 已写入`);
438	}
439	
440	/** 计算SOON因子命中 */
441	function computeFactors(stage, bl, meta, daysSinceMsg, lastSenderIsMe) {
442	  const factors = [];
443	  const t = TODAY_DATE;
444	
445	  switch (stage) {
446	    case '需求探索': {
447	      const d = parseDate(bl.S1);
448	      if (!d) break;
449	      const days = daysBetween(d, t);
450	      if (days < 1) break;
451	      const hitIdx = rhythmHit(days, RHYTHM.S1, 'S1');
452	      if (hitIdx >= 0) {
453	        const rhythmDay = RHYTHM.S1[hitIdx];
454	        factors.push({ factor: 'S1 该深挖需求了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S1 });
455	      }
456	      break;
457	    }
458	    case '报价已发': {
459	      const d = parseDate(bl.S2);
460	      if (!d) break;
461	      const days = daysBetween(d, t);
462	      if (days < 1) break;
463	      const hitIdx = rhythmHit(days, RHYTHM.S2, 'S2');
464	      if (hitIdx >= 0) {
465	        const rhythmDay = RHYTHM.S2[hitIdx];
466	        factors.push({ factor: 'S2 该追问了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S2 });
467	      }
468	      break;
469	    }
470	    case '谈判中': {
471	      const d = parseDate(bl.S3);
472	      if (!d) break;
473	      const days = daysBetween(d, t);
474	      if (days < 1) break;
475	      const hitIdx = rhythmHit(days, RHYTHM.S3, 'S3');
476	      if (hitIdx >= 0) {
477	        const rhythmDay = RHYTHM.S3[hitIdx];
478	        factors.push({ factor: 'S3 该推进了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S3 });
479	      }
480	      break;
481	    }
482	    case '待付款': {
483	      const d = parseDate(bl.S4);
