/** 计算SOON因子命中 */
function computeFactors(stage, bl, meta, daysSinceMsg, lastSenderIsMe) {
  const factors = [];
  const t = TODAY_DATE;

  switch (stage) {
    case '需求探索': {
      const d = parseDate(bl.S1);
      if (!d) break;
      const days = daysBetween(d, t);
      if (days < 1) break;
      const hitIdx = rhythmHit(days, RHYTHM.S1, 'S1');
      if (hitIdx >= 0) {
        const rhythmDay = RHYTHM.S1[hitIdx];
        factors.push({ factor: 'S1 该深挖需求了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S1 });
      }
      break;
    }
    case '报价已发': {
      const d = parseDate(bl.S2);
      if (!d) break;
      const days = daysBetween(d, t);
      if (days < 1) break;
      const hitIdx = rhythmHit(days, RHYTHM.S2, 'S2');
      if (hitIdx >= 0) {
        const rhythmDay = RHYTHM.S2[hitIdx];
        factors.push({ factor: 'S2 该追问了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S2 });
      }
      break;
    }
    case '谈判中': {
      const d = parseDate(bl.S3);
      if (!d) break;
      const days = daysBetween(d, t);
      if (days < 1) break;
      const hitIdx = rhythmHit(days, RHYTHM.S3, 'S3');
      if (hitIdx >= 0) {
        const rhythmDay = RHYTHM.S3[hitIdx];
        factors.push({ factor: 'S3 该推进了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S3 });
      }
      break;
    }
    case '待付款': {
      const d = parseDate(bl.S4);
      if (!d) break;
      const days = daysBetween(d, t);
      if (days < 1) break;
      const hitIdx = rhythmHit(days, RHYTHM.S4, 'S4');
      if (hitIdx >= 0) {
        const rhythmDay = RHYTHM.S4[hitIdx];
        const lastIdx = RHYTHM.S4.length - 1;
        const isDegraded = (hitIdx === lastIdx && days > rhythmDay + 1);
        factors.push({ factor: 'S4 该催款了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S4, degraded: isDegraded });
      }
      break;
    }
    case '待发货': {
      // S5a: 双基线
      if (bl.S5a_A) {
        const daysA = daysBetween(parseDate(bl.S5a_A), t);
        const interval = s5aInterval(meta);
        if (daysA >= interval && daysA % interval === 0) {
          factors.push({ factor: 'S5a 该更新进度了', days: daysA, interval, baseline: bl.S5a_A, priority: 'normal' });
        }
      }
      // S5a-B: 承诺发货日超期检查（需外部填写 committed_ship_date）
      if (meta.committed_ship_date && bl.S5a_A) {
        const shipDate = parseDate(meta.committed_ship_date);
        if (shipDate && t > shipDate) {
          const overdue = daysBetween(shipDate, t);
          factors.push({ factor: 'S5a 该更新进度了(超期)', days: overdue, priority: 'high', reason: '超承诺发货日' });
        }
      }
      break;
    }
    case '已发货/在途': {
      const d = parseDate(bl.S6);
      if (!d) break;
      const days = daysBetween(d, t);
      const interval = s6Interval(meta);
      if (days >= 1 && days % interval === 0) {
        factors.push({ factor: 'S6 该更新物流了', days, rhythmDay: days, baseline: bl.S6, interval });
      }
      break;
    }
    case '已签收': {
      if (bl.S7a) {
        const d = parseDate(bl.S7a);
        if (d) {
          const days = daysBetween(d, t);
          if (days >= 1) {
            const hitIdx = rhythmHit(days, RHYTHM.S7a, 'S7a');
            if (hitIdx >= 0) {
              const rhythmDay = RHYTHM.S7a[hitIdx];
              factors.push({ factor: 'S7a 该回访了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S7a });
            }
          }
        }
      }
      if (bl.S7b) {
        const d = parseDate(bl.S7b);
        if (d) {
          const days = daysBetween(d, t);
          if (days >= 1) {
            const rhythm = meta.customer_type === '样品单' ? RHYTHM.S7b_sample : RHYTHM.S7b_bulk;
            const hitIdx = rhythmHit(days, rhythm);
            if (hitIdx >= 0) {
              const rhythmDay = rhythm[hitIdx];
              factors.push({ factor: 'S7b 该推返单了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S7b });
            }
          }
        }
      }
      break;
    }
    case '售后': {
      const d = parseDate(bl.S8);
      if (!d) break;
      const days = daysBetween(d, t);
      if (days < 1) break;
      const hitIdx = rhythmHit(days, RHYTHM.S8, 'S8');
      if (hitIdx >= 0) {
        const rhythmDay = RHYTHM.S8[hitIdx];
        factors.push({ factor: 'S8 该收尾了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S8 });
      }
      break;
    }
    case '待返单': {
      if (bl.S9) {
        const d = parseDate(bl.S9);
        if (d) {
          const days = daysBetween(d, t);
          if (days >= 1) {
            const rhythm = meta.customer_type === '样品单' ? RHYTHM.S9_sample : RHYTHM.S9_bulk;
            const hitIdx = rhythmHit(days, rhythm, 'S9');
            if (hitIdx >= 0) {
              const rhythmDay = rhythm[hitIdx];
              factors.push({ factor: 'S9 该接触了', days, rhythmDay, intervalIndex: hitIdx, baseline: bl.S9 });
            }
          }
        }
      }
      break;
    }
  }

  return factors;
}

/** 因子命中统计 */
function summarizeFactors(soonCustomers) {
  const factorCounts = {};
  for (const c of soonCustomers) {
    for (const f of c.factors) {
      const key = f.factor.split('(')[0].trim();
      factorCounts[key] = (factorCounts[key] || 0) + 1;
    }
  }
  return factorCounts;
}

